def classify(code):
    if 200 <= code < 300:
        return 'ok'
    if 400 <= code < 500:
        return 'client_error'
    if 500 <= code < 600:
        return 'server_error'
    return 'other'
for c in [200, 400, 503]:
    print(c, classify(c))

FORBIDDEN = {'document_id', 'email', 'phone', 'full_name'}
payload = {'address': 'x', 'document_id': '123'}
leak = FORBIDDEN & set(payload)
print('blocked', bool(leak), leak)

ALLOWED = {'address', 'city', 'country'}
def allowed_for_public_geocoder(payload):
    return set(payload) <= ALLOWED
print(allowed_for_public_geocoder({'address': 'a', 'city': 'Lima', 'country': 'PE'}))
print(allowed_for_public_geocoder({'address': 'a', 'document_id': 'x'}))

def valid_lat_lon(lat, lon):
    return -90 <= lat <= 90 and -180 <= lon <= 180
print(valid_lat_lon(-12.04, -77.04), valid_lat_lon(100, 0))

ALLOWED = {'address', 'city', 'country'}
def allowed_for_public_geocoder(payload):
    return set(payload.keys()) <= ALLOWED
print(allowed_for_public_geocoder({'address': 'x', 'city': 'y', 'country': 'PE'}))

def valid_lat_lon(lat, lon):
    return -90 <= float(lat) <= 90 and -180 <= float(lon) <= 180
print(valid_lat_lon(-12.05, -77.04))

def as_relationship_signal(km):
    if km is None:
        return {'signal': None, 'note': 'missing_geo'}
    return {'signal': max(0.0, 1.0 - min(km, 50) / 50), 'note': 'geosignal_not_verdict'}
print(as_relationship_signal(1.2))
